kernel_src="""

#include "kernel_operator.h"
#include "kernel_gelu.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr uint32_t TILETemp = 3;

class KernelGeluCustom {
public:
    __aicore__ inline KernelGeluCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        // Constants for GELU: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
        c1_ = 0.7978845608028654f;  // sqrt(2/pi)
        c2_ = 0.044715f;
        half_ = 0.5f;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, TILETemp, tileLen_ * sizeof(float));

        // Get Tanh temporary buffer size
        const uint32_t tanhTmpSize = GetTanhTmpSize(tileLen);
        pipe_.InitBuffer(tmpBufQueue_, 1, tanhTmpSize);
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Tile-granularity grid-stride for better load balance
        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        // Prefetch first tile
        uint32_t curLen = totalLen_ - base;
        if (curLen > tileLen_) curLen = tileLen_;
        CopyIn(base, curLen);

        while (true) {
            // Prefetch next tile for overlap
            const uint32_t nextBase = base + strideElems;
            uint32_t nextLen = 0;
            if (nextBase < totalLen_) {
                nextLen = totalLen_ - nextBase;
                if (nextLen > tileLen_) nextLen = tileLen_;
                CopyIn(nextBase, nextLen);
            }

            Compute(curLen);
            CopyOut(base, curLen);

            if (nextLen == 0) break;
            base = nextBase;
            curLen = nextLen;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> tmp0 = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> tmp1 = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> tmp2 = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::LocalTensor<float> tanhBuf = tmpBufQueue_.AllocTensor<uint8_t>();

        // tmp0 = x^3
        AscendC::Muls(tmp0, xLocal, xLocal, len);
        AscendC::Muls(tmp0, tmp0, xLocal, len);

        // tmp1 = 0.044715 * x^3
        AscendC::Muls(tmp1, tmp0, c2_, len);

        // tmp1 = x + 0.044715 * x^3
        AscendC::Adds(tmp1, tmp1, xLocal, len);

        // tmp1 = sqrt(2/pi) * (x + 0.044715 * x^3)
        AscendC::Muls(tmp1, tmp1, c1_, len);

        // tmp2 = tanh(sqrt(2/pi) * (x + 0.044715 * x^3))
        AscendC::Tanh(tmp2, tmp1, tanhBuf, len);

        // tmp1 = 1 + tanh(...)
        AscendC::Adds(tmp1, tmp2, 1.0f, len);

        // y = 0.5 * x * (1 + tanh(...))
        AscendC::Muls(yLocal, xLocal, tmp1, len);
        AscendC::Muls(yLocal, yLocal, half_, len);

        tmpBufQueue_.FreeTensor(tanhBuf);
        tmpQueue_.FreeTensor(tmp0);
        tmpQueue_.FreeTensor(tmp1);
        tmpQueue_.FreeTensor(tmp2);
        outQueueY_.EnQue<float>(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, TILETemp> tmpQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpBufQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    float c1_ {0.7978845608f};
    float c2_ {0.044715f};
    float half_ {0.5f};
};

extern "C" __global__ __aicore__ void gelu_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelGeluCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength);
    op.Process();
}
